import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../auth/AuthContext';

const initialRegister = {
  email: '',
  phone: '',
  username: '',
  password: '',
  role: 'DONOR',
};

const initialLogin = {
  email: '',
  password: '',
};

const demoCredentials = {
  admin: {
    label: 'Admin Demo',
    email: 'admin@blooddonation.com',
    password: 'SecurePass@123',
  },
  donor: {
    label: 'Donor Demo',
    email: 'donor@blooddonation.com',
    password: 'SecurePass@123',
  },
};

function AuthPage() {
  const navigate = useNavigate();
  const { login, register, setFlash } = useAuth();

  const [mode, setMode] = useState('login');
  const [registerForm, setRegisterForm] = useState(initialRegister);
  const [loginForm, setLoginForm] = useState(initialLogin);
  const [busy, setBusy] = useState(false);

  function applyDemo(type) {
    const creds = demoCredentials[type];
    if (!creds) {
      return;
    }

    setMode('login');
    setLoginForm({
      email: creds.email,
      password: creds.password,
    });
  }

  async function handleRegister(event) {
    event.preventDefault();
    setBusy(true);
    try {
      await register(registerForm);
      navigate('/verify');
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    } finally {
      setBusy(false);
    }
  }

  async function handleLogin(event) {
    event.preventDefault();
    setBusy(true);
    try {
      await login(loginForm);
      navigate('/dashboard');
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    } finally {
      setBusy(false);
    }
  }

  return (
    <div className="auth-shell">
      <div className="auth-wrap">
        <section className="panel auth-showcase">
          <p className="eyebrow">Secure Access</p>
          <h2>CareFlow Identity Gateway</h2>
          <p>
            Sign in to manage donor and recipient operations, coordinate emergency workflows,
            and monitor verified activity from one platform.
          </p>

          <div className="auth-feature-list">
            <article>
              <h3>OTP and Verification</h3>
              <p>Email and phone verification flows are integrated after registration.</p>
            </article>
            <article>
              <h3>Role Based Security</h3>
              <p>Donor, recipient, and admin access stay isolated and policy-controlled.</p>
            </article>
            <article>
              <h3>Operational Visibility</h3>
              <p>Track requests, matches, and notifications in real time after sign-in.</p>
            </article>
          </div>

          <div className="auth-credential-card">
            <h4>Demo Credentials</h4>
            <p>Use autofill for quick testing:</p>
            <div className="auth-demo-actions">
              <button type="button" className="btn-ghost" onClick={() => applyDemo('admin')}>Use Admin Demo</button>
              <button type="button" className="btn-ghost" onClick={() => applyDemo('donor')}>Use Donor Demo</button>
            </div>
            <div className="demo-line"><strong>Admin:</strong> {demoCredentials.admin.email} / {demoCredentials.admin.password}</div>
            <div className="demo-line"><strong>Donor:</strong> {demoCredentials.donor.email} / {demoCredentials.donor.password}</div>
          </div>
        </section>

        <section className="panel auth-card auth-form-card">
          <p className="eyebrow">Portal Access</p>
          <h2>{mode === 'login' ? 'Welcome back' : 'Create your account'}</h2>
          <p className="auth-subtext">
            {mode === 'login'
              ? 'Login to continue your workflow securely.'
              : 'Register your account and continue with verification.'}
          </p>

          <div className="auth-switch">
            <button
              type="button"
              className={mode === 'login' ? 'active' : ''}
              onClick={() => setMode('login')}
            >
              Login
            </button>
            <button
              type="button"
              className={mode === 'register' ? 'active' : ''}
              onClick={() => setMode('register')}
            >
              Register
            </button>
          </div>

          {mode === 'login' ? (
            <form onSubmit={handleLogin} className="auth-form-grid">
              <label>
                Email
                <input
                  type="email"
                  placeholder="you@example.com"
                  value={loginForm.email}
                  onChange={(e) => setLoginForm((prev) => ({ ...prev, email: e.target.value }))}
                  required
                />
              </label>
              <label>
                Password
                <input
                  type="password"
                  placeholder="Enter your password"
                  value={loginForm.password}
                  onChange={(e) => setLoginForm((prev) => ({ ...prev, password: e.target.value }))}
                  required
                />
              </label>
              <button type="submit" className="btn-solid" disabled={busy}>{busy ? 'Authenticating...' : 'Login to Portal'}</button>
            </form>
          ) : (
            <form onSubmit={handleRegister} className="auth-form-grid">
              <label>
                Email
                <input
                  type="email"
                  placeholder="you@example.com"
                  value={registerForm.email}
                  onChange={(e) => setRegisterForm((prev) => ({ ...prev, email: e.target.value }))}
                  required
                />
              </label>
              <label>
                Phone
                <input
                  placeholder="+91xxxxxxxxxx"
                  value={registerForm.phone}
                  onChange={(e) => setRegisterForm((prev) => ({ ...prev, phone: e.target.value }))}
                  required
                />
              </label>
              <label>
                Username
                <input
                  placeholder="Choose a username"
                  value={registerForm.username}
                  onChange={(e) => setRegisterForm((prev) => ({ ...prev, username: e.target.value }))}
                  required
                />
              </label>
              <label>
                Password
                <input
                  type="password"
                  placeholder="Create a strong password"
                  value={registerForm.password}
                  onChange={(e) => setRegisterForm((prev) => ({ ...prev, password: e.target.value }))}
                  required
                />
              </label>
              <label>
                Role
                <select
                  value={registerForm.role}
                  onChange={(e) => setRegisterForm((prev) => ({ ...prev, role: e.target.value }))}
                >
                  <option value="DONOR">DONOR</option>
                  <option value="RECIPIENT">RECIPIENT</option>
                  <option value="ADMIN">ADMIN</option>
                </select>
              </label>
              <button type="submit" className="btn-solid" disabled={busy}>{busy ? 'Creating account...' : 'Register and Continue'}</button>
            </form>
          )}

          <p className="top-space auth-footer-link">
            Looking for platform details first? <Link to="/">Go to landing page</Link>
          </p>
        </section>
      </div>
    </div>
  );
}

export default AuthPage;
